const crypto = global.get("crypto");
const fs = global.get("fs");
const path = global.get("path");

function normStr(v) { return (v ?? "").toString().trim(); }

function generateInstallId() {
    if (crypto && typeof crypto.randomUUID === "function") return crypto.randomUUID();
    return "sef-" + Date.now().toString(36) + "-" + Math.random().toString(36).slice(2, 10);
}

const PREMIUM_FILE = "/config/smart_energy_finance_premium.json";
let installId = null;
let createdAt = null;
let fileStatus = "unknown";

if (!fs || !path) {
    node.status({ fill: "red", shape: "ring", text: "fs/path unavailable" });
    node.error("PREMIUM STORAGE INIT -> fs/path unavailable in functionGlobalContext", msg);
    return null;
}

try {
    if (fs.existsSync(PREMIUM_FILE)) {
        const raw = fs.readFileSync(PREMIUM_FILE, "utf8");
        const data = JSON.parse(raw);
        installId = normStr(data.install_id);
        createdAt = data.created_at || null;
        fileStatus = installId ? "loaded" : "invalid_file";
    } else {
        fileStatus = "missing_file";
    }
} catch (e) {
    node.warn("PREMIUM STORAGE INIT -> read error: " + e.message);
    fileStatus = "read_error";
}

if (!installId) {
    installId = generateInstallId();
    createdAt = Date.now();
    const dataToSave = { version: 1, install_id: installId, created_at: createdAt };
    try {
        fs.mkdirSync(path.dirname(PREMIUM_FILE), { recursive: true });
        fs.writeFileSync(PREMIUM_FILE, JSON.stringify(dataToSave, null, 2), "utf8");
        fileStatus = "created";
    } catch (e) {
        node.status({ fill: "red", shape: "ring", text: "write error" });
        node.error("PREMIUM STORAGE INIT -> write error: " + e.message, msg);
        return null;
    }
}

global.set("premium.install_id", installId);
global.set("premium.install_created_at", createdAt);

node.status({ fill: "green", shape: "dot", text: `install_id ${fileStatus}` });

msg.payload = msg.payload && typeof msg.payload === "object" ? msg.payload : {};
msg.payload.premium_storage = { install_id: installId, created_at: createdAt, file_status: fileStatus, file: PREMIUM_FILE };
return msg;

