   SVP|premium|INSTALL_ID|SIGNATURE
   ========================= */
const crypto = global.get("crypto");
function normStr(v) { return (v ?? "").toString().trim(); }
const LICENSE_SECRET = "SVP_2026_9f7c2e51b4d84f38a1e9c7b6d5e4f301_ULTRA_LONG_SECRET";
function signPayload(payload) {
    return crypto.createHmac("sha256", LICENSE_SECRET).update(payload, "utf8").digest("hex");
}
function safeEqual(a, b) {
    const aa = Buffer.from(String(a || ""), "utf8");
    const bb = Buffer.from(String(b || ""), "utf8");
    if (aa.length !== bb.length) return false;
    return crypto.timingSafeEqual(aa, bb);
}
const premiumKey = normStr(global.get("premium.key"));
const installId = normStr(global.get("premium.install_id"));
let premiumActive = false;
let premiumStatus = "missing_key";
let premiumTier = null;
if (!crypto) premiumStatus = "crypto_missing";
else if (!installId) premiumStatus = "missing_install_id";
else if (!premiumKey) premiumStatus = "missing_key";
else {
    const parts = premiumKey.split("|");
    if (parts.length !== 4) premiumStatus = "invalid_format";
    else {
        const prefix = normStr(parts[0]);
        const tier = normStr(parts[1]);
        const licenseInstallId = normStr(parts[2]);
        const signature = normStr(parts[3]);
        if (prefix !== "SVP") premiumStatus = "invalid_prefix";
        else if (tier !== "premium") premiumStatus = "invalid_tier";
        else if (!licenseInstallId) premiumStatus = "missing_license_install_id";
        else if (!signature) premiumStatus = "missing_signature";
        else if (licenseInstallId !== installId) premiumStatus = "install_id_mismatch";
        else {
            const payload = `${prefix}|${tier}|${licenseInstallId}`;
            const expected = signPayload(payload);
            if (!safeEqual(signature, expected)) premiumStatus = "invalid_signature";
            else {
                premiumActive = true;
                premiumStatus = "valid";
                premiumTier = "premium";
                global.set("premium.last_valid", Date.now());
            }
        }
    }
}
global.set("premium.active", premiumActive);
global.set("premium.status", premiumStatus);
global.set("premium.tier", premiumTier);
const premiumState = { install_id: installId || null, active: premiumActive, status: premiumStatus, tier: premiumTier };
if (premiumActive) node.status({ fill: "green", shape: "dot", text: "Premium active" });
else if (["invalid_format","invalid_prefix","invalid_tier","missing_license_install_id","missing_signature","install_id_mismatch","invalid_signature","crypto_missing"].includes(premiumStatus)) node.status({ fill: "red", shape: "ring", text: "Premium " + premiumStatus });
else node.status({ fill: "yellow", shape: "ring", text: "Free / " + premiumStatus });
msg.payload = msg.payload && typeof msg.payload === "object" ? msg.payload : {};
msg.payload.premium = premiumState;
return msg;

