function style(kind = "neutral") {
    if (!HAS_CARD_MOD) return {};
    const colors = {
        orange: "#f59e0b",
        green: "#22c55e",
        blue: "#38bdf8",
        purple: "#a855f7",
        cyan: "#06b6d4",
        neutral: "#64748b",
        red: "#ef4444"
    };
    return {
        card_mod: {
            style: `
                ha-card {
                    border-top: 4px solid ${colors[kind] || colors.neutral};
                    border-radius: 18px;
                    overflow: hidden;
                    box-shadow: 0 6px 18px rgba(0,0,0,0.12);
                }
            `
        }
    };
}

function titleCard(title, subtitle, kind) {
    return {
        type: "markdown",
        content: `# ${title}\n## ${subtitle}`,
        ...style(kind)
    };
}

function tile(entityId, name, icon, kind) {
    return {
        type: "tile",
        entity: entityId,
        name,
        icon,
        vertical: false,
        hide_state: false,
        ...style(kind)
    };
}

function grid(columns, cards) {
    return {
        type: "grid",
        columns,
        square: false,
        cards: cards.filter(Boolean)
    };
}

function stack(cards) {
    return {
        type: "vertical-stack",
        cards: cards.filter(Boolean)
    };
}

function entitiesCard(title, entities, kind) {
    return {
        type: "entities",
        title,
        show_header_toggle: false,
        entities,
        ...style(kind)
    };
}

function donutCard(title, series, kind = "neutral", height = 420) {
    if (!HAS_APEXCHARTS) {
        return entitiesCard(title, series.map(s => s.entity), kind);
    }

    return {
        type: "custom:apexcharts-card",
        chart_type: "donut",
        header: {
            show: true,
            title,
            show_states: true,
            colorize_states: true
        },
        all_series_config: {
            float_precision: 2,
            show: {
                in_header: true,
                legend_value: true
            }
        },
        series,
        apex_config: {
            chart: { height },
            legend: { show: true, position: "bottom" },
            dataLabels: { enabled: true },
            stroke: { width: 2 }
        },
        ...style(kind)
    };
}

